cat /Users/ainchorsoc2a/.openclaw/workspace/state/asset-registry.json | python3 -c "
import json, sys, os, urllib.request, urllib.error, time

data = json.load(sys.stdin)
assets = data['assets']

NOTION_KEY_FILE = os.path.expanduser('~/.config/notion/api_key')
if not os.path.exists(NOTION_KEY_FILE):
    print('ERROR: Notion API key not found')
    sys.exit(1)

with open(NOTION_KEY_FILE) as f:
    NOTION_KEY = ***

today = '2026-07-18'

def update_notion_page(page_id, status, last_updated, notion_key):
    payload = json.dumps({
        'properties': {
            'Status': {'select': {'name': status}},
            'Last Updated': {'date': {'start': last_updated}}
        }
    }).encode()

    req = urllib.request.Request(
        f'https://api.notion.com/v1/pages/{page_id}',
        data=payload,
        headers={
            'Authorization': f'Bearer {notion_key}',
            'Notion-Version': '2022-06-28',
            'Content-Type': 'application/json'
        },
        method='PATCH'
    )
    try:
        with urllib.request.urlopen(req, timeout=15) as resp:
            return True
    except urllib.error.HTTPError as e:
        body = e.read().decode()
        return f'HTTP {e.code}: {body[:200]}'

updated = 0
archived = 0
errors = 0

for asset in assets:
    page_id = asset.get('notion_page_id')
    if not page_id:
        continue

    status = asset['status']
    last_updated = asset.get('last_updated', today)

    result = update_notion_page(page_id, status, last_updated, NOTION_KEY)
    if result is True:
        if status == 'Archived':
            archived += 1
        else:
            updated += 1
        print(f'  ✓ {asset[\"name\"]} → Status={status}, Last Updated={last_updated}')
    else:
        errors += 1
        print(f'  ✗ {asset[\"name\"]}: {result}')

    time.sleep(0.35)

print(f'\\nNotion update complete: {updated} Current updated, {archived} Archived, {errors} errors')
"

